function isRecord(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function pad3(value) {
  return String(value).padStart(3, '0');
}

function slugify(value) {
  return String(value || 'topic')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
